// Validate configuration and build prompt templates
const config = $input.item.json;

if (!config.directory_path) throw new Error('directory_path is required');
if (!config.lora_token) throw new Error('lora_token is required');
if (!/^[\w-]+$/.test(config.lora_token)) {
  throw new Error(`Invalid LoRA token: "${config.lora_token}". Use only letters, numbers, underscores, dashes.`);
}

const prompts = {
  general: "Provide a concise, objective description suitable for training. Describe what is visible: subjects present, key elements, composition/framing, lighting direction/quality/intensity, color palette, materials/textures, and any notable spatial context. Avoid brand names, identities, opinions, or narrative language.",
  object: "Describe this image for object LoRA training. Focus on environment and optics: lighting direction/quality/intensity and shadows/reflections, camera–subject relationship (angle, distance, depth of field, framing), background context and support surfaces, and general color/material cues visible without naming or identifying the object specifically. Avoid brand names, unique labels, or subjective adjectives.",
  character: "Describe this image for character LoRA training. Emphasize pose and positioning in space, lighting direction/quality/intensity and shadows, camera–subject relationship (angle, distance, focal-length feel, depth of field, framing), and surroundings. Do not list facial identity details or unique identifiers; avoid brand/style words.",
  style: "Describe the overall scene succinctly, then the dominant color palette and the quality of light (direction, softness/hardness, contrast, time-of-day feel). Mention composition tendencies or rendering approach if evident (e.g., minimal, high-contrast, soft-gradation). Do not identify brands or subjects.",
  scene: "Describe the setting and visible elements with attention to spatial layout and depth cues, composition/framing lines, lighting direction/quality/intensity, and palette. Include materials/textures of major surfaces. Avoid identities, brands, and subjective adjectives."
};

const template = config.prompt_template || 'general';
const basePrompt = prompts[template] || prompts.general;
const fullPrompt = `CRITICAL: Begin your description with exactly this trigger token: "${config.lora_token}"\n\nAfter the trigger token, provide the description following these guidelines:\n\n${basePrompt}`;

return {
  json: {
    ...config,
    prompt: fullPrompt,
    started_at: new Date().toISOString(),
    cost_per_image: 0.002,
    total_cost: 0,
    images_processed: 0,
    images_failed: 0
  }
};

// Cross-platform image file discovery using Node.js fs module
const fs = require('fs');
const path = require('path');

const config = $input.item.json;
const dirPath = config.directory_path.replace(/\\/g, '/');
const supportedExtensions = ['.jpg', '.jpeg', '.png', '.webp'];

function getAllImageFiles(dir, results = []) {
  try {
    const items = fs.readdirSync(dir, { withFileTypes: true });

    for (const item of items) {
      const fullPath = path.join(dir, item.name).replace(/\\/g, '/');

      if (item.isDirectory()) {
        // Recursively process subdirectories (aspect buckets)
        getAllImageFiles(fullPath, results);
      } else if (item.isFile()) {
        const ext = path.extname(item.name).toLowerCase();
        if (supportedExtensions.includes(ext)) {
          results.push(fullPath);
        }
      }
    }
  } catch (error) {
    throw new Error(`Failed to read directory "${dir}": ${error.message}`);
  }

  return results;
}

const imageFiles = getAllImageFiles(dirPath);

if (imageFiles.length === 0) {
  throw new Error(`No images found in: ${dirPath}\n\nSupported formats: .jpg, .jpeg, .png, .webp`);
}

return {
  json: {
    ...config,
    image_files: imageFiles,
    total_images: imageFiles.length
  }
};

// Prepare individual image items from file list
const data = $input.item.json;
const imageFiles = data.image_files;

// Create individual items for each image
const items = imageFiles.map((filepath, index) => {
  const filename = filepath.split('/').pop();
  const imageId = filename.replace(/\.[^/.]+$/, '');

  return {
    json: {
      filepath: filepath,
      filename: filename,
      image_id: imageId,
      index: index + 1,
      total_images: imageFiles.length,
      lora_token: data.lora_token,
      prompt: data.prompt,
      prompt_template: data.prompt_template,
      enable_refinement: data.enable_refinement,
      quality_threshold: data.quality_threshold,
      max_retries: data.max_retries,
      job_id: data.job_id,
      retry_count: 0,
      processing_started_at: new Date().toISOString()
    }
  };
});

return items;

// Convert image binary to base64 data URI for OpenAI Vision API
const item = $input.item;

// Handle read errors
if (item.json.error || !item.binary?.data) {
  return {
    json: {
      ...item.json,
      error: item.json.error || 'Failed to read image file',
      skip_api_call: true
    }
  };
}

const binaryData = item.binary.data;
const mimeType = binaryData.mimeType || 'image/jpeg';
const base64 = binaryData.data;

return {
  json: {
    ...item.json,
    image_data_uri: `data:${mimeType};base64,${base64}`,
    file_size_bytes: Buffer.from(base64, 'base64').length
  }
};

// Extract caption from API response or handle errors
const item = $input.item.json;
const prevData = $('Code — Convert to Base64 URI').item.json;

let caption = null;
let error = null;
let api_call_successful = false;

// Check for API errors
if (item.error) {
  error = item.error.message || 'API call failed';
} else if (!item.choices || !item.choices[0] || !item.choices[0].message) {
  error = 'Invalid API response structure';
} else {
  caption = item.choices[0].message.content.trim();
  api_call_successful = true;
}

return {
  json: {
    ...prevData,
    raw_caption: caption,
    caption: caption,
    error: error,
    api_call_successful: api_call_successful,
    captioning_attempt: prevData.retry_count + 1
  }
};

