// Update caption after refinement
const item = $input.item.json;
const prevData = $('Code — Score Quality (9 Checks)').item.json;

let caption = prevData.caption;
let refinement_applied = false;

if (!item.error && item.choices && item.choices[0]) {
  caption = item.choices[0].message.content.trim();
  refinement_applied = true;
}

return {
  json: {
    ...prevData,
    caption: caption,
    refinement_applied: refinement_applied,
    original_caption: prevData.raw_caption
  }
};

// Re-score after refinement
const item = $input.item.json;
const caption = item.caption || '';
const loraToken = item.lora_token;

const words = caption.split(/\s+/);
const checks = {
  hasMinLength: words.length >= 10,
  hasMaxLength: words.length <= 200,
  hasSubject: /\b(person|character|object|subject|figure|individual|entity)\b/i.test(caption),
  hasVisualDetails: /\b(color|light|texture|surface|material|pattern|shape|form)\b/i.test(caption),
  noErrors: !/\b(error|unable|cannot|sorry|failed|unclear)\b/i.test(caption),
  notTooVague: !/^(this is|the image shows|this image|here we see)/i.test(caption),
  hasLighting: /\b(light|shadow|bright|dark|illuminat|glow|shine)\b/i.test(caption),
  hasComposition: /\b(foreground|background|angle|perspective|composition|framing|frame|position)\b/i.test(caption),
  loraTokenValid: caption.toLowerCase().startsWith(loraToken.toLowerCase()) && 
                  (caption.toLowerCase().match(new RegExp(loraToken.toLowerCase(), 'g')) || []).length === 1
};

const passedChecks = Object.values(checks).filter(Boolean).length;
const totalChecks = Object.keys(checks).length;
const qualityScore = passedChecks / totalChecks;

return {
  json: {
    ...item,
    quality_checks: checks,
    quality_score: qualityScore,
    passed_checks: passedChecks,
    total_checks: totalChecks,
    quality_passed: qualityScore >= item.quality_threshold,
    quality_improved: qualityScore > (item.quality_score || 0)
  }
};

// Prepare text file path and content
const item = $input.item.json;
const filepath = item.filepath;
const caption = item.caption || '';

// Create .txt path by replacing file extension
const txtPath = filepath.replace(/\.[^/.]+$/, '.txt');

return {
  json: {
    ...item,
    txt_path: txtPath,
    txt_content: caption,
    ready_to_save: true
  }
};

// Mark file write result
const item = $input.item.json;

const writeSuccessful = !item.error;

return {
  json: {
    ...item,
    file_written: writeSuccessful,
    processing_completed_at: new Date().toISOString()
  }
};

// Generate comprehensive summary report
const allItems = $input.all();
const config = $('📝 Config — Edit Settings').item.json;

const successful = allItems.filter(item => item.json.file_written);
const failed = allItems.filter(item => !item.json.file_written || item.json.error);
const refined = allItems.filter(item => item.json.refinement_applied);

const loraTokenAccurate = allItems.filter(item => {
  const caption = item.json.caption || '';
  const token = item.json.lora_token || '';
  return caption.toLowerCase().startsWith(token.toLowerCase());
});

const totalWordCounts = successful.reduce((sum, item) => {
  const words = (item.json.caption || '').split(/\s+/).length;
  return sum + words;
}, 0);

const avgCaptionLength = successful.length > 0 ? totalWordCounts / successful.length : 0;
const loraTokenAccuracy = allItems.length > 0 ? loraTokenAccurate.length / allItems.length : 0;
const totalCost = allItems.length * 0.002; // $0.002 per image with gpt-4o

const lowQualityItems = allItems.filter(item => 
  item.json.quality_score && item.json.quality_score < config.quality_threshold
);

const report = {
  job_id: config.job_id,
  started_at: config.started_at,
  completed_at: new Date().toISOString(),
  total_images: allItems.length,
  successful: successful.length,
  failed: failed.length,
  refinements_applied: refined.length,
  lora_token_accuracy: loraTokenAccuracy,
  lora_token_accurate_count: loraTokenAccurate.length,
  avg_caption_length_words: Math.round(avgCaptionLength * 10) / 10,
  captioning_cost_usd: Math.round(totalCost * 100) / 100,
  low_quality_count: lowQualityItems.length,
  quality_threshold: config.quality_threshold,
  failed_files: failed.map(item => ({
    filename: item.json.filename,
    error: item.json.error || 'Unknown error'
  })),
  low_quality_files: lowQualityItems.map(item => ({
    filename: item.json.filename,
    quality_score: Math.round(item.json.quality_score * 100) / 100,
    failed_checks: Object.entries(item.json.quality_checks || {})
      .filter(([k, v]) => !v)
      .map(([k]) => k)
  })),
  status: failed.length === 0 ? 'completed_successfully' : 'completed_with_errors'
};

return {
  json: report
};

